// Extract and sanitise all expected fields from the POST body.
// Defaults are applied here — validation happens in the next node.

const body = $input.first().json;

return [{
  json: {
    service_user_name : (body.service_user_name  || '').trim(),
    dob               : (body.dob                || '').trim(),
    referral_source   : (body.referral_source    || '').trim(),
    referrer_name     : (body.referrer_name      || '').trim(),
    referrer_contact  : (body.referrer_contact   || '').trim(),
    support_needs     : (body.support_needs      || '').trim(),
    urgency_level     : (body.urgency_level      || 'standard').trim().toLowerCase(),
    received_at       : new Date().toISOString()
  }
}];

// Rules:
//   service_user_name — required
//   referral_source   — required
//   urgency_level     — must be emergency | urgent | standard (defaults to standard if invalid)

const d = $input.first().json;
const errors = [];
const VALID_URGENCY = ['emergency', 'urgent', 'standard'];

if (!d.service_user_name)
  errors.push('service_user_name is required');

if (!d.referral_source)
  errors.push('referral_source is required');

if (d.urgency_level && !VALID_URGENCY.includes(d.urgency_level)) {
  errors.push(`urgency_level must be one of: ${VALID_URGENCY.join(', ')}`);
  d.urgency_level = 'standard'; // fallback to safe default
}

return [{
  json: {
    ...d,
    _valid  : errors.length === 0,
    _errors : errors
  }
}];

// Format: ENV-REF-{YEAR}-{RANDOM6}
// Charset excludes ambiguous chars (O, 0, I, 1) for readability.

const { _valid, _errors, ...data } = $input.first().json;

const year  = new Date().getFullYear();
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let rand6   = '';
for (let i = 0; i < 6; i++)
  rand6 += chars[Math.floor(Math.random() * chars.length)];

return [{
  json: {
    ...data,
    referral_id : `ENV-REF-${year}-${rand6}`,
    status      : 'received'
  }
}];

